import functools
import logging
from typing import Callable, Any
from dataclasses import dataclass, field

logger = logging.getLogger(__name__)

@dataclass
class PermissionContext:
    """Holds the current agent's granted permissions for this execution."""
    agent_id: str
    granted_scopes: set[str] = field(default_factory=set)
    task_id: str = ""

    def has_scope(self, scope: str) -> bool:
        return scope in self.granted_scopes

    def has_all_scopes(self, scopes: list[str]) -> bool:
        return all(self.has_scope(s) for s in scopes)


class AuthorizationError(Exception):
    """Raised when an agent attempts to use a tool without required permissions."""
    pass


def requires_permissions(*required_scopes: str):
    """
    Decorator that enforces permission checks before tool execution.
    The decorated function must accept a 'permission_context' keyword argument.
    """
    def decorator(func: Callable) -> Callable:
        # Attach metadata for static analysis and auditing
        func._required_scopes = list(required_scopes)

        @functools.wraps(func)
        def wrapper(*args, permission_context: PermissionContext, **kwargs) -> Any:
            missing = [
                scope for scope in required_scopes
                if not permission_context.has_scope(scope)
            ]
            if missing:
                logger.warning(
                    "Authorization denied",
                    extra={
                        "agent_id": permission_context.agent_id,
                        "task_id": permission_context.task_id,
                        "tool": func.__name__,
                        "required_scopes": list(required_scopes),
                        "missing_scopes": missing,
                        "granted_scopes": list(permission_context.granted_scopes)
                    }
                )
                raise AuthorizationError(
                    f"Agent '{permission_context.agent_id}' attempted to call "
                    f"'{func.__name__}' but is missing scopes: {missing}"
                )

            logger.info(
                "Tool call authorized",
                extra={
                    "agent_id": permission_context.agent_id,
                    "tool": func.__name__,
                    "scopes_used": list(required_scopes)
                }
            )
            return func(*args, permission_context=permission_context, **kwargs)
        return wrapper
    return decorator


# Tool definitions with explicit permission requirements
@requires_permissions('database:read')
def get_user_profile(user_id: str, permission_context: PermissionContext) -> dict:
    # Safe to execute — permissions verified by decorator
    return {"user_id": user_id, "name": "Alice"}


@requires_permissions('database:read', 'database:write')
def update_user_profile(user_id: str, data: dict, permission_context: PermissionContext) -> bool:
    # Requires both read and write — decorator enforces this
    return True


@requires_permissions('email:send')
def send_notification(to: str, subject: str, permission_context: PermissionContext) -> bool:
    return True


# Example: agent with read-only permissions trying to write
read_only_context = PermissionContext(
    agent_id="support-agent-001",
    granted_scopes={'database:read'},
    task_id="task-abc123"
)

try:
    update_user_profile(
        user_id="user-42",
        data={"name": "Bob"},
        permission_context=read_only_context
    )
except AuthorizationError as e:
    print(f"Blocked: {e}")
    # Output: Blocked: Agent 'support-agent-001' attempted to call
    # 'update_user_profile' but is missing scopes: ['database:write']

import boto3
import json
import time
import logging
from typing import Optional, Any
from functools import lru_cache

logger = logging.getLogger(__name__)

class AgentSecretsClient:
    """
    Secure secrets client for AI agents.
    Fetches secrets from AWS Secrets Manager with caching and rotation support.
    Logs every secret access for audit purposes.
    """
    def __init__(self, agent_id: str, region: str = 'us-east-1', cache_ttl_seconds: int = 300):
        self.agent_id = agent_id
        self.cache_ttl = cache_ttl_seconds
        self._client = boto3.client('secretsmanager', region_name=region)
        self._cache: dict[str, tuple[Any, float]] = {}  # {secret_id: (value, expiry)}

    def get_secret(self, secret_id: str, key: Optional[str] = None) -> str:
        """
        Retrieve a secret by ID. Optionally extract a specific key from JSON secrets.
        Caches secrets for cache_ttl_seconds to reduce API calls.
        """
        # Check cache first
        cached_value, expiry = self._cache.get(secret_id, (None, 0))
        if cached_value is not None and time.time() < expiry:
            logger.info(
                "Secret accessed from cache",
                extra={"agent_id": self.agent_id, "secret_id": secret_id, "source": "cache"}
            )
            return self._extract_key(cached_value, key)

        # Fetch from Secrets Manager
        try:
            response = self._client.get_secret_value(SecretId=secret_id)
            secret_value = response.get('SecretString') or \
                           response.get('SecretBinary', b'').decode('utf-8')

            # Cache with TTL
            self._cache[secret_id] = (secret_value, time.time() + self.cache_ttl)

            logger.info(
                "Secret fetched from Secrets Manager",
                extra={
                    "agent_id": self.agent_id,
                    "secret_id": secret_id,
                    "source": "secrets_manager",
                    # Never log the actual secret value
                    "secret_length": len(secret_value)
                }
            )
            return self._extract_key(secret_value, key)

        except self._client.exceptions.ResourceNotFoundException:
            logger.error(
                "Secret not found",
                extra={"agent_id": self.agent_id, "secret_id": secret_id}
            )
            raise
        except self._client.exceptions.AccessDeniedException:
            logger.error(
                "Access denied to secret — possible misconfiguration or attack",
                extra={"agent_id": self.agent_id, "secret_id": secret_id}
            )
            raise

    def _extract_key(self, secret_value: str, key: Optional[str]) -> str:
        if key is None:
            return secret_value
        try:
            secret_dict = json.loads(secret_value)
            return secret_dict[key]
        except (json.JSONDecodeError, KeyError) as e:
            raise ValueError(f"Cannot extract key '{key}' from secret: {e}")

    def invalidate_cache(self, secret_id: str) -> None:
        """Force cache invalidation when rotation is detected."""
        if secret_id in self._cache:
            del self._cache[secret_id]
            logger.info(
                "Secret cache invalidated",
                extra={"agent_id": self.agent_id, "secret_id": secret_id}
            )

    def rotate_aware_get(self, secret_id: str, key: Optional[str] = None) -> str:
        """
        Fetch secret and handle rotation gracefully.
        If a 401/403 is received using the cached secret, invalidate and retry.
        """
        self.invalidate_cache(secret_id)
        return self.get_secret(secret_id, key)


# Usage in agent tools — no hardcoded credentials anywhere
class DatabaseTool:
    def __init__(self, agent_id: str):
        self.secrets = AgentSecretsClient(agent_id=agent_id)

    def get_connection_string(self) -> str:
        # Secrets fetched at runtime, never stored in code or env vars
        host = self.secrets.get_secret('prod/database/credentials', key='host')
        password = self.secrets.get_secret('prod/database/credentials', key='password')
        username = self.secrets.get_secret('prod/database/credentials', key='username')
        return f"postgresql://{username}:{password}@{host}:5432/prod"

    def query(self, sql: str) -> list:
        conn_string = self.get_connection_string()
        # Use conn_string to establish connection...
        logger.info("Database query executed", extra={"sql_hash": hash(sql)})
        return []


# Initialize tool — agent_id used for all audit logs
db_tool = DatabaseTool(agent_id="analytics-agent-007")
conn = db_tool.get_connection_string()
print("Connection established using rotated credentials from Secrets Manager")
